body:
I encountered an issue while using master-branch Verilator related to randomization.

While union and struct constrained randomization are supported after the #5344 commit, unconstrained randomization for union remains unsupported.
To address this, I wrote a simple patch that adds support for unconstrained randomization of union. I tested it with a custom test case, and it works as expected.

Two tests to run are:
Test 1:
```
typedef struct packed {
    rand bit [3:0] a;
    rand bit [11:0] b;
} PackedStruct;

typedef union packed {
    PackedStruct s;
    bit [15:0] raw_bits;
} InnerPackedUnion;

typedef union packed {
    InnerPackedUnion u1;
    bit [15:0] raw_data;
} OuterPackedUnion;

class UnionInUnionTest;
    rand OuterPackedUnion my_outer_union;

    function new();
        my_outer_union.raw_data = 16'b0;
    endfunction

endclass

module union_in_union_unconstrained_test;
    UnionInUnionTest test;

    initial begin
        test = new();
        repeat(10) begin
            if (!test.randomize()) $error("Randomization failed");
            $display("Inner Union Struct: a: %b, b: %b, raw_bits: %b", test.my_outer_union.u1.s.a, test.my_outer_union.u1.s.b, test.my_outer_union.u1.raw_bits);
            $display("Outer Union: raw_data: %b", test.my_outer_union.raw_data);
        end
        $finish;
    end
endmodule

```
Test 2:
```
typedef struct packed {
    rand bit [3:0] a;
    rand bit [7:0] b;
} PackedStruct;

typedef union packed {
    PackedStruct s;
    bit [11:0] raw_bits;
} PackedUnion;

class StructInUnionTest;
    rand PackedUnion my_union;

    function new();
        my_union.raw_bits = 12'b0;
    endfunction

endclass

module struct_in_union_unconstrained_test;
    StructInUnionTest test;

    initial begin
        test = new();
        repeat(10) begin
            if (!test.randomize()) $error("Randomization failed");
            $display("Struct: a: %b, b: %b", test.my_union.s.a, test.my_union.s.b);
            $display("Union : raw_bits: %b", test.my_union.raw_bits);
        end
        $finish;
    end
endmodule
```
